<?php

require __DIR__ . '/config.php';
$errors = [];

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $last = trim($_POST['lastName'] ?? '');
    $first = trim($_POST['firstName'] ?? '');
    $middle = trim($_POST['middleName'] ?? '');
    
    // New: birthdate instead of age
    $birthdate = $_POST['birthdate'] ?? '';
    $age = null;
    if ($birthdate) {
        $birthDateObj = DateTime::createFromFormat('Y-m-d', $birthdate);
        if ($birthDateObj) {
            $today = new DateTime();
            $age = $today->diff($birthDateObj)->y;
        } else {
            $errors[] = 'Invalid birthdate format';
        }
    } else {
        $errors[] = 'Birthdate required';
    }
    
    $gender = $_POST['gender'] ?? '';
    $civil = $_POST['civilStatus'] ?? '';
    $address = trim($_POST['address'] ?? '');
    $course = trim($_POST['course'] ?? '');
    $year = (int) ($_POST['yearGraduated'] ?? 0);
    $employment = $_POST['employment'] ?? 'Unemployed';
    $occupation = trim($_POST['occupation'] ?? '');
    $company = trim($_POST['company'] ?? '');
    $work = trim($_POST['workAddress'] ?? '');
    
    // New fields
    $yearsOfService = !empty($_POST['yearsOfService']) ? (int) $_POST['yearsOfService'] : null;
    $recentWork = trim($_POST['recentWork'] ?? '');

    // Validation
    if (!$last) $errors[] = 'Last name required';
    if (!$first) $errors[] = 'First name required';
    if (!$birthdate) $errors[] = 'Birthdate required';
    if (!$gender) $errors[] = 'Gender required';
    if (!$civil) $errors[] = 'Civil status required';
    if (!$address) $errors[] = 'Address required';
    if (!$course) $errors[] = 'Course required';
    if ($year < 1960) $errors[] = 'Valid year of graduation required';

    if (empty($errors)) {
        $stmt = $pdo->prepare("INSERT INTO alumni (last_name, first_name, middle_name, age, birth_date, gender, civil_status, address, course, year_graduated, employment_status, occupation, company_agency, work_address, years_of_service, recent_work) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");
        $stmt->execute([
            $last, $first, $middle ?: null,
            $age, $birthdate,
            $gender, $civil, $address, $course, $year,
            $employment,
            $occupation ?: null,
            $company ?: null,
            $work ?: null,
            $yearsOfService,
            $recentWork ?: null
        ]);
        header('Location: /api/success.php?name=' . urlencode($first));
        exit;
    }
}

?>
