      <div class="field"><label>Civil Status <span>*</span></label><select name="civilStatus" required><option value="">Select</option><?php foreach(['Single','Married','Widowed','Separated'] as $c) { $s = (($_POST['civilStatus']??'') == $c) ? 'selected' : ''; echo "<option $s>$c</option>"; } ?></select></div>
