      <div class="field"><label>Year Graduated <span>*</span></label><select name="yearGraduated" required><?php $current = date('Y'); for($y=$current+6; $y>=1960; $y--) { $s = (($_POST['yearGraduated']??$current-1) == $y) ? 'selected' : ''; echo "<option $s>$y</option>"; } ?></select></div>
    </div>

    <div class="sec">Employment Details</div>
    <div class="grid g2">
      <div class="field"><label>Employment Status <span>*</span></label><div class="radio-group"><?php $emp = $_POST['employment'] ?? 'Employed'; foreach(['Employed','Unemployed','Self-employed','Retired'] as $e) { $c = ($emp == $e) ? 'checked' : ''; echo "<label><input type='radio' name='employment' value='$e' $c> $e</label>"; } ?></div></div>
