<script>
  const radios = document.querySelectorAll('input[name="employment"]');
  function toggle() {
    const val = document.querySelector('input[name="employment"]:checked')?.value;
    const disable = (val === 'Unemployed' || val === 'Retired');
    document.getElementById('occupation').disabled = disable;
    document.getElementById('company').disabled = disable;
    document.getElementById('workAddress').disabled = disable;
  }
  radios.forEach(r => r.addEventListener('change', toggle));
  toggle();
</script>
